export function SpinnerIcon({ className }: SpinnerIconProps) {
  return (
    <svg
      width="16"
      height="16"
      viewBox="0 0 16 16"
      fill="none"
      aria-hidden="true"
      className={className}
    >
      <g transform="translate(8 8)">
        {SPINNER_BARS.map((bar, index) => (
          <rect
            key={index}
            x="-1"
            y="-6.5"
            width="2"
            height="3.5"
            rx="1"
            fill="currentColor"
            fillOpacity={bar.opacity}
            transform={`rotate(${index * 45})`}
          />
        ))}
      </g>
    </svg>
  );
}
